// ==============================
// 1. ANALYZE EXISTING FILES (HUB INDEX)
// ==============================

async function scanAllPages() {
  const pages = [];

  try {
    const allFiles = await fs.readdir(OUTPUT_DIR, { recursive: true });
    for (const file of allFiles) {
      const fullPath = path.join(OUTPUT_DIR, file);
      const stat = await fs.stat(fullPath);
      if (!stat.isFile()) continue;

      // Only HTML
      if (!path.extname(file).toLowerCase().endsWith(".html")) continue;

      const content = await fs.readFile(fullPath, "utf8");
      const relativePath = file.replace(/\\/g, "/");

      // Infer type from filename
      let type = "generic";
      if (relativePath.includes("event-")) type = "event";
      if (relativePath.includes("hotels-in-")) type = "city";
      if (relativePath.includes("daily-")) type = "daily";
      if (relativePath.includes("keyword-")) type = "keyword";

      pages.push({
        file: relativePath,
        absPath: fullPath,
        type,
        content,
      });
    }

    await fs.writeJSON(HUBS_INDEX_PATH, pages, { spaces: 2 });
    console.log(`seven-file-specials.js: built ${pages.length}‑page SEO hub index.`);

    return pages;
  } catch (err) {
    console.error("Error scanning pages:", err.message);
    return [];
  }
}

// ==============================
// 2. BUILD CROSS‑LINK MAPS
// ==============================

function buildCrossLinkMap(pages) {
  const cityMap = new Map();
  const eventMap = new Map();
  const keywordMap = new Map();

  pages.forEach((page) => {
    let cityMatch;
    let eventMatch;
    let keywordMatch;

    // City
    const cityMatchRegex = /hotels-in-([a-z0-9-]+)/;
    const cityMatchResult = page.file.match(cityMatchRegex);
    if (cityMatchResult) {
      cityMatch = cityMatchResult[1];
      if (!cityMap.has(cityMatch)) cityMap.set(cityMatch, []);
      cityMap.get(cityMatch).push(page.file);
    }

    // Event
    const eventMatchRegex = /event-([a-z0-9-]+)/;
    const eventMatchResult = page.file.match(eventMatchRegex);
    if (eventMatchResult) {
      eventMatch = eventMatchResult[1];
      if (!eventMap.has(eventMatch)) eventMap.set(eventMatch, []);
      eventMap.get(eventMatch).push(page.file);
    }

    // Keyword
    const keywordMatchRegex = /keyword-([a-z0-9-]+)/;
    const keywordMatchResult = page.file.match(keywordMatchRegex);
    if (keywordMatchResult) {
      keywordMatch = keywordMatchResult[1];
      if (!keywordMap.has(keywordMatch)) keywordMap.set(keywordMatch, []);
      keywordMap.get(keywordMatch).push(page.file);
    }
  });

  return { cityMap, eventMap, keywordMap };
}

// ==============================
// 3. WRITE SEO‑RICH META + SCHEMA INTO A PAGE
// ==============================

function injectSeoMeta(content, lang, pageType, tokens = {}) {
  const {
    city = "",
    event = "",
    keyword = "",
    day = "",
  } = tokens;

  // Language variants
  const langNames = {
    en: "English",
    es: "Español",
    pt: "Português",
    de: "Deutsch",
    fr: "Français",
    it: "Italiano",
    zh: "中文",
    ru: "Русский",
    ar: "العربية",
    ja: "日本語",
    ko: "한국어",
    tr: "Türkçe",
    pl: "Polski",
    nl: "Nederlands",
    no: "Norsk",
    se: "Svenska",
    fa: "فارسی",
    th: "ไทย",
    id: "Indonesia",
    vi: "Tiếng Việt",
  };

  const langName = langNames[lang] || "language";

  // Generate SEO‑friendly title and description
  let title,
      description;

  if (pageType === "city") {
    title = `Best hotels in ${city}${day ? ` – Day ${day} 2026` : ""} | Booking.com affiliate`;
    description = `Find the best hotels in ${city}${day ? `, Day ${day} 2026,` : ""} with Booking.com affiliate links (${BOOKING.HOME}) and Skyscanner flights (${SKY.HOME}).`;

  } else if (pageType === "event") {
    title = `Hotels for ${event} 2026 | ${city} and nearby cities`;
    description = `Hotel guide for ${event} 2026 travelers with Booking.com affiliate links (${BOOKING.HOME}) and Skyscanner flight search (${SKY.HOME}).`;

  } else if (pageType === "keyword") {
    title = `${keyword} – Best hotels 2026 | Booking.com affiliate`;
    description = `Search page for "${keyword}" with Booking.com affiliate links (${BOOKING.HOME}) and Skyscanner flight options (${SKY.HOME}).`;

  } else if (pageType === "daily") {
    title = `Hotels in ${city} – Day ${day} 2026 | Booking.com guide`;
    description = `Daily hotel selection in ${city} for Day ${day} 2026 with Booking.com affiliate links (${BOOKING.HOME}) and Skyscanner.${day ? "" : " "}`;

  } else {
    title = `Hotel guide for travelers 2026 | Booking.com and Skyscanner`;
    description = `Comprehensive hotel guide using Booking.com affiliate links (${BOOKING.HOME}) and Skyscanner (${SKY.HOME}) for 2026 travelers.`;
  }

  // Schema markup
  let schemaType = "WebPage";
  let schemaJson = `
  {
    "@context": "https://schema.org",
    "@type": "WebPage",
    "name": "${title}",
    "description": "${description.replace(/"/g, '\\"')}",
    "publisher": {
      "@type": "Organization",
      "name": "YourHotelGuide",
      "url": "https://yourdomain.com/"
    }
  }`;

  if (pageType === "city") {
    schemaType = "CollectionPage";
    schemaJson = `
  {
    "@context": "https://schema.org",
    "@type": "CollectionPage",
    "name": "${title}",
    "description": "${description.replace(/"/g, '\\"')}",
    "mainEntity": {
      "@type": "ItemList",
      "name": "Hotels in ${city}",
      "itemListElement": [
        {
          "@type": "ListItem",
          "position": 1,
          "item": {
            "@type": "Hotel",
            "name": "Sample Hotel Name"
          }
        }
      ]
    },
    "publisher": {
      "@type": "Organization",
      "name": "YourHotelGuide",
      "url": "https://yourdomain.com/"
    }
  }`;
  }

  // Inject meta + schema
  const metaTags = `
  <meta charset="utf-8">
  <title>${title}</title>
  <meta name="description" content="${description.replace(/"/g, '\\"')}">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <meta name="language" content="${lang}">
  <meta name="robots" content="index, follow">
  <meta name="keywords" content="${[ ...BOOKING_KEYWORDS, ...COMMON_DESTINATIONS ].join(", ")}">
  <link rel="canonical" href="https://yourdomain.com/${pageType === "city" ? `hotels-in-${city.replace(" ", "-").toLowerCase()}` : pageType === "event" ? `event-${event}` : keyword ? keyword : "index"}.html">
  <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet">
`;

  const schemaTag = `
  <script type="application/ld+json">
  ${schemaJson}
  </script>
`;

  // Replace or inject
  const head = /(<head[^>]*>)([\s\S]*?)(<\/head>)/gi;
  if (head.test(content)) {
    return content.replace(
      head,
      (_, before, inner, after) => {
        const newInner = inner.replace(/<\/head>/, "");
        return `${before}
${metaTags}
${newInner}
${schemaTag}
${after}`;
      }
    );
  } else {
    return `<head>${metaTags}</head>${content}`;
  }
}

// ==============================
// 4. ADD CROSS‑LINKS TO A PAGE
// ==============================

function injectCrossLinks(content, pageType, tokens, hubMap) {
  const {
    city = "",
    event = "",
    keyword = "",
  } = tokens;

  let crossLinksHtml = "";

  if (city && hubMap.cityMap.has(city.replace(" ", "-"))) {
    const cityPages = hubMap.cityMap.get(city.replace(" ", "-"));
    if (cityPages.length > 0) {
      crossLinksHtml += `
  <h3>More hotel guides for ${city}</h3>
  <ul>
    ${cityPages
      .slice(0, 10)
      .map(
        (file) =>
          `<li><a href="/${file}">${file.replace("hotels-in-", "").replace(/-/g, " ")}</a></li>`
      )
      .join("\n")}
  </ul>`;
    }
  }

  if (event && hubMap.eventMap.has(event)) {
    const eventPages = hubMap.eventMap.get(event);
    if (eventPages.length > 0) {
      crossLinksHtml += `
  <h3>More hotel guides for ${event}</h3>
  <ul>
    ${eventPages
      .slice(0, 8)
      .map(
        (file) =>
          `<li><a href="/${file}">${file.replace("event-", "").replace(/-/g, " ")}</a></li>`
      )
      .join("\n")}
  </ul>`;
    }
  }

  if (keyword && hubMap.keywordMap.has(keyword)) {
    const keywordPages = hubMap.keywordMap.get(keyword);
    if (keywordPages.length > 0) {
      crossLinksHtml += `
  <h3>More pages for "${keyword}"</h3>
  <ul>
    ${keywordPages
      .slice(0, 8)
      .map(
        (file) =>
          `<li><a href="/${file}">${file.replace("keyword-", "").replace(/-/g, " ")}</a></li>`
      )
      .join("\n")}
  </ul>`;
    }
  }

  // Insert before </body>
  if (crossLinksHtml) {
    const body = /<body[^>]*>([\s\S]*)<\/body>/i;
    if (body.test(content)) {
      return content.replace(
        body,
        (whole, bodyInner) => {
          return `<body>
${bodyInner}
  <div class="container py-4">
    <h2>Other pages you might like</h2>
    ${crossLinksHtml}
  </div>
</body>`;
        }
      );
    }
  }

  return content;
}

// ==============================
// 5. PROCESS ONE PAGE FILE
// ==============================

function inferPageTypeAndTokens(file) {
  const fileLower = file.toLowerCase();

  // Tokens
  const tokens = {
    city: "",
    event: "",
    keyword: "",
    day: "",
  };

  // City
  const cityMatch = fileLower.match(/hotels-in-([a-z0-9-]+)/);
  if (cityMatch) {
    tokens.city = cityMatch[1].replace(/-/g, " ");
  }

  // Event
  const eventMatch = fileLower.match(/event-([a-z0-9-]+)/);
  if (eventMatch) {
    tokens.event = eventMatch[1].replace(/-/g, " ");
  }

  // Keyword
  const keywordMatch = fileLower.match(/keyword-([a-z0-9-]+)/);
  if (keywordMatch) {
    tokens.keyword = keywordMatch[1].replace(/-/g, " ");
  }

  // Day
  const dayMatch = fileLower.match(/day-([0-9]+)/);
  if (dayMatch) {
    tokens.day = dayMatch[1];
  }

  // Page type
  let pageType;
  if (cityMatch) pageType = "city";
  else if (eventMatch) pageType = "event";
  else if (keywordMatch) pageType = "keyword";
  else if (fileLower.includes("daily-")) pageType = "daily";
  else pageType = "generic";

  return { pageType, tokens };
}

async function processPageFile(fullPath, relativePath, lang, hubMap) {
  const content = await fs.readFile(fullPath, "utf8");

  const { pageType, tokens } = inferPageTypeAndTokens(relativePath);

  let newContent = injectSeoMeta(content, lang, pageType, tokens);
  newContent = injectCrossLinks(newContent, pageType, tokens, hubMap);

  await fs.writeFile(fullPath, newContent);
  console.log(`✓ SEO + cross‑link updated: ${relativePath}`);
}

